#pragma once#include "Vehicle.h"#include <iostream>using namespace std;class Motorcycle : public Vehicle {public:    Motorcycle() : Vehicle("Motorcycle", "cc", 2025, "Unknown", 0) {}    Motorcycle(string m, int y, string n, int eng): Vehicle("Motorcycle", m, y, n, eng) {}    void startEngine() override {         cout << "Motorcycle Engine (" << engineNumber << ") started with a kick.\n";    }    void stopEngine() override {        cout << "Motorcycle Engine stopped.\n";    }};